head.script:
//전역변수
scwin.memJson = $c.data.getMemInfo(); // 로그인 정보를 가져온다.
scwin.privAdmin = scwin.memJson.privAdmin; // ADMIN 권한 CHK : 'T' : ADMIN , 'F': ADMIN 아님

scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd; // 소속 자회사
scwin.vLoginCoClsCd = $c.gus.cfIsNull(scwin.memJson.coClsCd) ? '' : scwin.memJson.coClsCd; // 회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.vUserHomeClsCd = scwin.memJson.userHomeClsCd; // 사용자소속구분코드
scwin.isSubCompany = false;

scwin.vAcctDeptCd= scwin.memJson.acctDeptCd;
scwin.vUserEmpNo= scwin.memJson.empNo;        // 사용자사원번호
scwin.vUserId= scwin.memJson.userId;        // 사용자ID

scwin.stYm = "";
scwin.endYm = "";
scwin.submitDt = "";
scwin.txtCoClsCd = "";

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
	cbx_previewCheck.setValue(1);
};

//-------------------------------------------------------------------------
// 파일 확장자 체크
//-------------------------------------------------------------------------
scwin.f_CheckFileExt = function(ext, path) {
    ext = ext.toUpperCase();
    path = path.toUpperCase();
    let elen = ext.length;
    let flen = path.length;
    return (ext === path.substring((flen - elen), flen));
}

/**
 * 엑셀 파일 업로드
 */
scwin.f_excelUpload = async function () {
    if(excelUdc.getUpExt() == "1") {
        let options = {
            "fileName": "gridDataUpload.csv",
            "status": "C",
            "header":1,
            "type": "1",
            "startRowIndex":0,
            "footerExist":0,
        };

        ds_excel.removeAll();

        await $c.data.uploadGridViewCSV(gr_excel, options);
    } else {
        let options = {
            "fileName": "gridDataUpload.xlsx",
            "status": "C",
            "headerExist":1,
            "useMaxByteLength": ",",
            "type": "1",
            "startRowIndex":0,
            "footerExist":0,
        };
        ds_excel.removeAll();

        await $c.data.uploadGridViewExcel(gr_excel, options);
    }
};

//-------------------------------------------------------------------------
// 엑셀 Upload
//-------------------------------------------------------------------------
scwin.f_Upload = async function(){   
    $c.gus.cfProgressWinOpen();

    if (ds_excel.getRowCount == 0) {
        $c.gus.cfProgressWinClose();
        await $c.win.alert(MSG_CM_ERR_003);
        return;
    }

    if (scwin.f_AddRowUploaded()) {
        $c.gus.cfProgressWinClose();
        await $c.win.alert("업로드작업이 완료되었습니다.");
    }
}

//-------------------------------------------------------------------------
// 업로드 자료 추가
//-------------------------------------------------------------------------
scwin.f_AddRowUploaded = function () {
    if (ds_excel.getRowCount() > 0) {

        ds_evid.removeAll();

        for (let i=0; i < ds_excel.getRowCount(); i++) {
            let row = ds_evid.insertRow();

            ds_evid.setCellData(row,"sellVatNo",ds_excel.getCellData(i,"sellVatNo"));
        }
    }

    totalRows.setValue(ds_evid.getRowCount());
    return true;
}


//-------------------------------------------------------------------------
// 매출세금계산서발행
//-------------------------------------------------------------------------
scwin.f_OzReport = async function() {
    let param = "";

    if (ds_evid.getRowCount() === 0) {
        await $c.win.alert("발행할 세금계산서를 업로드 하세요");
        return;
    }

    for (let i = 0; i < ds_evid.getRowCount(); i++) {
        param = param + "," + ds_evid.getCellData(i, "sellVatNo");
    }

    let data = {
        odiName:"fi_401_01_09p",
        reportName: "/ac/fi/taxbiz/vatctrl/fi_401_01_09p.ozr",
        odiParam : {
            pchsSellCls: param.substring(1),
            coCd: scwin.vLoginCoCd
        },
        viewerParam : {},
        formParam: {}
    };
    await scwin.openPopup(data);
};

scwin.openPopup = async function(data){
    let opts = {
        id: "ozReportPopup",
        popupName: "오즈 리포트",
        modal: true,
        type: "browserPopup",
        width: 1000,
        height: 600,
        title: "오즈 리포트"
    };
    await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
}

scwin.btn_close_onclick = function (e) {
    $c.win.closePopup();
};

scwin.btn_print_onclick = function (e) {
    scwin.f_OzReport();
};

scwin.gr_excel_onfilereadend = function (value) {
    scwin.f_Upload();
};
